const input = $input.first().json;
const action = input.action || '';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const allCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.dataforseo&select=cred_key,cred_value',
  headers: pgHeaders
});
const creds = {};
for (const c of (allCreds || [])) creds[c.cred_key] = c.cred_value;
const login = creds.dataforseo_login;
const password = creds.dataforseo_password;
if (!login || !password) {
  return [{ json: { error: 'DataForSEO credentials not configured. Set both dataforseo_login (email) and dataforseo_password via add_credential.' } }];
}
const authHeader = 'Basic ' + Buffer.from(login + ':' + password).toString('base64');
const BASE = 'https://api.dataforseo.com/v3';

async function dfsCall(method, path, taskBody) {
  const opts = { method: method, url: BASE + path, headers: { 'Authorization': authHeader }, json: true };
  if (taskBody !== undefined && taskBody !== null) {
    opts.headers['Content-Type'] = 'application/json';
    opts.body = JSON.stringify(taskBody);
  }
  let res;
  try {
    res = await helpers.httpRequest(opts);
  } catch (e) {
    throw new Error('HTTP error: ' + (e.message || e));
  }
  if (!res || res.status_code !== 20000) {
    throw new Error('DataForSEO API error ' + (res && res.status_code) + ': ' + (res && res.status_message));
  }
  const task = (res.tasks || [])[0];
  if (!task) throw new Error('No task in response.');
  if (task.status_code !== 20000) {
    throw new Error('DataForSEO task error ' + task.status_code + ': ' + task.status_message);
  }
  return { result: task.result || [], cost: res.cost, time: res.time };
}

function trunc(s, n) {
  if (!s) return '';
  if (s.length <= n) return s;
  return s.substring(0, n) + '\n\n... (truncated at ' + n + ' chars).';
}
function fmtCost(meta) {
  const c = (meta.cost == null ? 0 : meta.cost);
  return '\n\n_Cost: $' + c.toFixed(4) + ' | Time: ' + (meta.time || '?') + '_';
}
function req_(v, name) {
  if (v === undefined || v === null || v === '') throw new Error('Parameter "' + name + '" is required.');
  return v;
}
function splitKeywords(s) {
  if (!s) return [];
  if (Array.isArray(s)) return s;
  return String(s).split(',').map(x => x.trim()).filter(Boolean);
}
function locInt(v) { return parseInt(v, 10); }

try {
  if (action === 'dfs_account_balance') {
    const m = await dfsCall('GET', '/appendix/user_data', null);
    const r = m.result[0] || {};
    let out = 'DataForSEO account: ' + (r.login || '?') + ' (TZ: ' + (r.timezone || '?') + ')';
    if (r.money) out += '\nBalance: $' + Number(r.money.balance || 0).toFixed(2) + ' | Lifetime spend: $' + Number(r.money.total || 0).toFixed(2);
    return [{ json: { result: out + fmtCost(m) } }];
  }

  if (action === 'dfs_serp_google_organic') {
    req_(input.keyword, 'keyword'); req_(input.location_code, 'location_code'); req_(input.language_code, 'language_code');
    const m = await dfsCall('POST', '/serp/google/organic/live/regular', [{ keyword: input.keyword, location_code: locInt(input.location_code), language_code: input.language_code, depth: parseInt(input.depth) || 10 }]);
    const r = m.result[0] || {};
    let out = 'Google SERP "' + r.keyword + '" (' + r.location_code + '/' + r.language_code + ')\nTotal results: ' + (r.se_results_count || 0) + '\n\n';
    for (const it of (r.items || [])) {
      if (it.type === 'organic') {
        out += '#' + it.rank_absolute + ' ' + it.domain + ' -- ' + it.title + '\n  ' + it.url + '\n';
        if (it.description) out += '  ' + it.description.substring(0,150) + '\n';
        out += '\n';
      }
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_serp_google_organic_advanced') {
    req_(input.keyword, 'keyword'); req_(input.location_code, 'location_code'); req_(input.language_code, 'language_code');
    const m = await dfsCall('POST', '/serp/google/organic/live/advanced', [{ keyword: input.keyword, location_code: locInt(input.location_code), language_code: input.language_code, depth: parseInt(input.depth) || 10 }]);
    const r = m.result[0] || {};
    let out = 'Google SERP advanced "' + r.keyword + '" (' + r.location_code + '/' + r.language_code + ')\nResults: ' + (r.se_results_count || 0) + ' | Item types: ' + (r.item_types || []).join(', ') + '\n\n';
    for (const it of (r.items || [])) {
      out += '#' + (it.rank_absolute || '-') + ' [' + it.type + ']';
      if (it.domain) out += ' ' + it.domain;
      if (it.title) out += ' -- ' + it.title;
      out += '\n';
      if (it.url) out += '  ' + it.url + '\n';
      if (it.description) out += '  ' + it.description.substring(0,150) + '\n';
      if (it.snippet) out += '  Snippet: ' + it.snippet.substring(0,150) + '\n';
      out += '\n';
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_search_volume') {
    const kws = splitKeywords(input.keywords);
    if (kws.length === 0) throw new Error('Parameter "keywords" is required (comma-separated list).');
    req_(input.location_code, 'location_code'); req_(input.language_code, 'language_code');
    const m = await dfsCall('POST', '/keywords_data/google_ads/search_volume/live', [{ keywords: kws, location_code: locInt(input.location_code), language_code: input.language_code }]);
    let out = 'Search volume (Google Ads, ' + input.location_code + '/' + input.language_code + '):\n\n';
    for (const r of (m.result || [])) {
      out += '- "' + r.keyword + '": vol=' + (r.search_volume || 0) + ', CPC=$' + Number(r.cpc || 0).toFixed(2) + ', comp=' + (r.competition || '?') + ' (idx ' + (r.competition_index || '?') + ')\n';
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_keywords_for_keywords') {
    const kws = splitKeywords(input.keywords);
    if (kws.length === 0) throw new Error('Parameter "keywords" is required.');
    req_(input.location_code, 'location_code'); req_(input.language_code, 'language_code');
    const m = await dfsCall('POST', '/keywords_data/google_ads/keywords_for_keywords/live', [{ keywords: kws, location_code: locInt(input.location_code), language_code: input.language_code, limit: parseInt(input.limit) || 30 }]);
    let out = 'Related keywords (Google Ads):\n\n';
    for (const r of (m.result || []).slice(0, 50)) {
      out += '- "' + r.keyword + '": vol=' + (r.search_volume || 0) + ', CPC=$' + Number(r.cpc || 0).toFixed(2) + ', comp=' + (r.competition || '?') + '\n';
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_google_trends') {
    const kws = splitKeywords(input.keywords);
    if (kws.length === 0) throw new Error('Parameter "keywords" is required.');
    req_(input.location_code, 'location_code');
    const body = { keywords: kws.slice(0,5), location_code: locInt(input.location_code) };
    if (input.date_from) body.date_from = input.date_from;
    if (input.date_to) body.date_to = input.date_to;
    const m = await dfsCall('POST', '/keywords_data/dataforseo_trends/explore/live', [body]);
    const r = m.result[0] || {};
    let out = 'Google Trends "' + kws.join(', ') + '":\n\n';
    for (const it of (r.items || [])) {
      out += 'Type: ' + it.type + '\n';
      const data = (it.data && Array.isArray(it.data)) ? it.data : (it.keywords ? it.keywords.map((k,i) => ({ keyword: k, value: (it.values && it.values[i]) || 0 })) : []);
      for (const point of data.slice(-12)) {
        out += '  ' + (point.date_from || point.date || point.keyword || '?') + ': ' + JSON.stringify(point.values || point.value || []) + '\n';
      }
      out += '\n';
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_keyword_overview') {
    req_(input.keyword, 'keyword'); req_(input.location_code, 'location_code'); req_(input.language_code, 'language_code');
    const m = await dfsCall('POST', '/dataforseo_labs/google/keyword_overview/live', [{ keywords: [input.keyword], location_code: locInt(input.location_code), language_code: input.language_code }]);
    let r = m.result[0] || {};
    if (r.items && r.items.length) r = r.items[0];
    const ki = r.keyword_info || {};
    const kp = r.keyword_properties || {};
    let out = 'Keyword overview "' + input.keyword + '":\n';
    out += '- Search volume: ' + (ki.search_volume || 0) + '/mo\n';
    out += '- CPC: $' + Number(ki.cpc || 0).toFixed(2) + '\n';
    out += '- Competition: ' + (ki.competition || '?') + ' (idx ' + (ki.competition_index || '?') + ')\n';
    if (kp.keyword_difficulty != null) out += '- Difficulty: ' + kp.keyword_difficulty + '/100\n';
    if (r.search_intent_info) out += '- Intent: ' + (r.search_intent_info.main_intent || '?') + '\n';
    if (r.serp_info && r.serp_info.serp_item_types) out += '- SERP features: ' + r.serp_info.serp_item_types.join(', ') + '\n';
    return [{ json: { result: out + fmtCost(m) } }];
  }

  if (action === 'dfs_keyword_ideas') {
    req_(input.keyword, 'keyword'); req_(input.location_code, 'location_code'); req_(input.language_code, 'language_code');
    const m = await dfsCall('POST', '/dataforseo_labs/google/keyword_ideas/live', [{ keywords: [input.keyword], location_code: locInt(input.location_code), language_code: input.language_code, limit: parseInt(input.limit) || 30 }]);
    const r = m.result[0] || {};
    let out = 'Keyword ideas for "' + input.keyword + '":\n\n';
    for (const it of (r.items || []).slice(0, 50)) {
      const ki = it.keyword_info || {};
      out += '- "' + it.keyword + '": vol=' + (ki.search_volume || 0) + ', CPC=$' + Number(ki.cpc || 0).toFixed(2) + ', comp=' + (ki.competition || '?') + '\n';
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_keyword_difficulty') {
    const kws = splitKeywords(input.keywords);
    if (kws.length === 0) throw new Error('Parameter "keywords" is required.');
    req_(input.location_code, 'location_code'); req_(input.language_code, 'language_code');
    const m = await dfsCall('POST', '/dataforseo_labs/google/bulk_keyword_difficulty/live', [{ keywords: kws, location_code: locInt(input.location_code), language_code: input.language_code }]);
    const r = m.result[0] || {};
    let out = 'Keyword difficulty:\n\n';
    for (const it of (r.items || [])) {
      out += '- "' + it.keyword + '": KD=' + (it.keyword_difficulty != null ? it.keyword_difficulty : '?') + '/100\n';
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_ranked_keywords') {
    req_(input.target, 'target'); req_(input.location_code, 'location_code'); req_(input.language_code, 'language_code');
    const m = await dfsCall('POST', '/dataforseo_labs/google/ranked_keywords/live', [{ target: input.target, location_code: locInt(input.location_code), language_code: input.language_code, limit: parseInt(input.limit) || 30 }]);
    const r = m.result[0] || {};
    let out = 'Ranked keywords for ' + input.target + ' (' + input.location_code + '/' + input.language_code + ')\nTotal: ' + (r.total_count || '?') + '\n\n';
    for (const it of (r.items || []).slice(0, 50)) {
      const k = (it.keyword_data && it.keyword_data.keyword) || it.keyword || '?';
      const pos = (it.ranked_serp_element && it.ranked_serp_element.serp_item) ? it.ranked_serp_element.serp_item.rank_absolute : '?';
      const vol = (it.keyword_data && it.keyword_data.keyword_info) ? (it.keyword_data.keyword_info.search_volume || 0) : 0;
      out += '#' + pos + ' "' + k + '" (vol=' + vol + ')\n';
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_competitors_domain') {
    req_(input.target, 'target'); req_(input.location_code, 'location_code'); req_(input.language_code, 'language_code');
    const m = await dfsCall('POST', '/dataforseo_labs/google/competitors_domain/live', [{ target: input.target, location_code: locInt(input.location_code), language_code: input.language_code, limit: parseInt(input.limit) || 20 }]);
    const r = m.result[0] || {};
    let out = 'Competitors for ' + input.target + ':\n\n';
    for (const it of (r.items || []).slice(0, 30)) {
      out += '- ' + it.domain + ' | intersections: ' + (it.intersections || 0) + ' | avg_pos: ' + (it.avg_position || '?') + '\n';
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_backlinks_summary') {
    req_(input.target, 'target');
    const m = await dfsCall('POST', '/backlinks/summary/live', [{ target: input.target }]);
    const r = m.result[0] || {};
    let out = 'Backlinks summary ' + input.target + ':\n';
    out += '- Backlinks: ' + (r.backlinks || 0) + '\n';
    out += '- Referring domains: ' + (r.referring_domains || 0) + '\n';
    out += '- Referring main domains: ' + (r.referring_main_domains || 0) + '\n';
    out += '- Rank: ' + (r.rank || '?') + '\n';
    return [{ json: { result: out + fmtCost(m) } }];
  }

  if (action === 'dfs_backlinks_referring_domains') {
    req_(input.target, 'target');
    const m = await dfsCall('POST', '/backlinks/referring_domains/live', [{ target: input.target, limit: parseInt(input.limit) || 30 }]);
    const r = m.result[0] || {};
    let out = 'Referring domains for ' + input.target + ' (total: ' + (r.total_count || '?') + '):\n\n';
    for (const it of (r.items || []).slice(0, 50)) {
      out += '- ' + it.domain + ' | rank: ' + (it.rank || '?') + ' | backlinks: ' + (it.backlinks || 0) + '\n';
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_backlinks_anchors') {
    req_(input.target, 'target');
    const m = await dfsCall('POST', '/backlinks/anchors/live', [{ target: input.target, limit: parseInt(input.limit) || 30 }]);
    const r = m.result[0] || {};
    let out = 'Anchor distribution for ' + input.target + ' (total: ' + (r.total_count || '?') + '):\n\n';
    for (const it of (r.items || []).slice(0, 50)) {
      out += '- "' + (it.anchor || '(empty)') + '" | backlinks: ' + (it.backlinks || 0) + ' | refdoms: ' + (it.referring_domains || 0) + '\n';
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_onpage_instant') {
    req_(input.url, 'url');
    const m = await dfsCall('POST', '/on_page/instant_pages', [{ url: input.url }]);
    let r = m.result[0] || {};
    if (r.items && r.items.length) r = r.items[0];
    let out = 'On-page audit ' + input.url + ':\n';
    out += '- HTTP status: ' + (r.status_code || '?') + '\n';
    if (r.meta) {
      out += '- Title: ' + (r.meta.title || '-') + '\n';
      out += '- Description: ' + (r.meta.description || '-') + '\n';
    }
    if (r.checks) {
      const fails = Object.entries(r.checks).filter(([k,v]) => v === false).map(([k]) => k);
      out += '- Failed checks: ' + (fails.length ? fails.join(', ') : 'none') + '\n';
    }
    if (r.page_timing) out += '- Page timing: ' + JSON.stringify(r.page_timing) + '\n';
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_lighthouse_audit') {
    req_(input.url, 'url');
    const forMobile = String(input.for_mobile || 'true').toLowerCase() === 'true';
    const m = await dfsCall('POST', '/on_page/lighthouse/live/json', [{ url: input.url, for_mobile: forMobile }]);
    const r = m.result[0] || {};
    let out = 'Lighthouse audit ' + input.url + ' (' + (forMobile ? 'mobile' : 'desktop') + '):\n';
    if (r.categories) {
      for (const [k, c] of Object.entries(r.categories)) {
        out += '- ' + (c.title || k) + ': ' + Math.round((c.score || 0) * 100) + '/100\n';
      }
    }
    if (r.audits) {
      const failing = Object.values(r.audits).filter(a => a && a.score != null && a.score < 0.5).slice(0, 8);
      if (failing.length) {
        out += '\nTop issues:\n';
        for (const a of failing) out += '- ' + (a.title || '?') + ' (score ' + (a.score || 0) + ')\n';
      }
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_domain_technologies') {
    req_(input.target, 'target');
    const m = await dfsCall('POST', '/domain_analytics/technologies/domain_technologies/live', [{ target: input.target }]);
    const r = m.result[0] || {};
    let out = 'Tech stack ' + input.target + ':\n';
    if (r.domain_rank) out += '- Domain rank: ' + r.domain_rank + '\n';
    if (r.country_iso_code) out += '- Country: ' + r.country_iso_code + '\n';
    if (r.technologies) {
      out += '\nTechnologies:\n';
      for (const [cat, items] of Object.entries(r.technologies)) {
        if (Array.isArray(items) && items.length) {
          out += '- ' + cat + ': ' + items.map(t => (typeof t === 'string' ? t : (t.name || t))).join(', ') + '\n';
        }
      }
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  if (action === 'dfs_my_business_info') {
    req_(input.keyword, 'keyword'); req_(input.location_code, 'location_code'); req_(input.language_code, 'language_code');
    const m = await dfsCall('POST', '/business_data/google/my_business_info/live', [{ keyword: input.keyword, location_code: locInt(input.location_code), language_code: input.language_code, depth: parseInt(input.depth) || 10 }]);
    const r = m.result[0] || {};
    let out = 'Google My Business "' + input.keyword + '" (' + input.location_code + '/' + input.language_code + '):\n\n';
    for (const it of (r.items || []).slice(0, 15)) {
      out += '- ' + (it.title || '?') + (it.rating ? ' *' + it.rating.value + ' (' + it.rating.votes_count + ')' : '') + '\n';
      if (it.address) out += '  ' + it.address + '\n';
      if (it.phone) out += '  Phone: ' + it.phone + '\n';
      if (it.url) out += '  ' + it.url + '\n';
      out += '\n';
    }
    return [{ json: { result: trunc(out, 5000) + fmtCost(m) } }];
  }

  return [{ json: { error: 'Unknown action: "' + action + '". Valid: dfs_account_balance, dfs_serp_google_organic, dfs_serp_google_organic_advanced, dfs_search_volume, dfs_keywords_for_keywords, dfs_google_trends, dfs_keyword_overview, dfs_keyword_ideas, dfs_keyword_difficulty, dfs_ranked_keywords, dfs_competitors_domain, dfs_backlinks_summary, dfs_backlinks_referring_domains, dfs_backlinks_anchors, dfs_onpage_instant, dfs_lighthouse_audit, dfs_domain_technologies, dfs_my_business_info.' } }];
} catch (e) {
  return [{ json: { error: 'DataForSEO call failed: ' + (e.message || String(e)) } }];
}
